from flask import Flask, request, jsonify
import pickle
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(func_name, *args, **kwargs):
    return f"{func_name}_{hash(str(args) + str(kwargs))}"

def load_cache(key):
    file_path = os.path.join(CACHE_DIR, key)
    if os.path.exists(file_path):
        with open(file_path, 'rb') as f:
            data = pickle.load(f)
            if time.time() - data['timestamp'] < data['ttl']:
                return data['value']
    return None

def save_cache(key, value, ttl):
    file_path = os.path.join(CACHE_DIR, key)
    with open(file_path, 'wb') as f:
        pickle.dump({'value': value, 'timestamp': time.time(), 'ttl': ttl}, f)

@app.route('/api', methods=['GET'])
def api():
    func_name = request.args.get('func')
    args = tuple(request.args.getlist('arg'))
    kwargs = {k: v for k, v in request.args.items() if k not in ['func', 'arg']}
    
    key = cache_key(func_name, *args, **kwargs)
    cached_data = load_cache(key)
    
    if cached_data is not None:
        return jsonify(cached_data), 200
    
    # Simulate expensive API call
    result = {
        'data': {'nested': [1, 2, 3], 'metadata': {'key': 'value'}},
        'timestamp': time.time()
    }
    
    ttl = 60 * 5  # Cache for 5 minutes
    save_cache(key, result['data'], ttl)
    
    return jsonify(result), 200

if __name__ == '__main__':
    app.run(debug=True)